#include <stdio.h>
#define MOD 1000000007
int dp[100005][105], cnt[105];
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= M; j++) {
                dp[i][j] = 0;
                cnt[j] = 0;
            }
        }
        for (int i = 1; i <= M; i++) {
            dp[1][i] = 1;
        }
        for (int i = 2; i <= N; i++) {
            for (int j = 1; j <= M; j++) {
                for (int k = 1; k <= M; k++) {
                    if (k != j) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 1; i <= M; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

