                for (int j = 0; j <= M; j++) {
                    dp[i][j] = 0;
                    cnt[j] = 0;
                }
            }
            for (int i = 1; i <= M; i++) {
                dp[1][i] = 1;
            }
            for (int i = 2; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    for (int k = 1; k <= M; k++) {
